#!/usr/bin/env bash
# Rebuild the slim libbt.a + matching headers and refresh the git-tracked
# prebuilt/ directory. See README.md for the why.
#
# Output:
#   out/                 — Docker scratch dir (large, gitignored)
#   prebuilt/lib/libbt.a — git-tracked slim library
#   prebuilt/include/bt/ — git-tracked matching headers
#   prebuilt/manifest.txt — provenance: framework version, IDF, lib-builder,
#                          defconfig hash. install.sh refuses on mismatch.
#
# Run from anywhere; resolves paths relative to the script.
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
DEFCONFIG="$SCRIPT_DIR/configs/defconfig.bleslim"
OUT_DIR="$SCRIPT_DIR/out"
PREBUILT_DIR="$SCRIPT_DIR/prebuilt"
IMAGE="espressif/esp32-arduino-lib-builder:latest"

if [ ! -f "$DEFCONFIG" ]; then
  echo "error: defconfig not found at $DEFCONFIG" >&2
  exit 1
fi

# Read which pioarduino framework this rebuild is targeting; recorded in the
# manifest so install.sh can refuse to install against a mismatched framework.
PIOARDUINO_PKG="$HOME/.platformio/packages/framework-arduinoespressif32-libs/package.json"
if [ ! -f "$PIOARDUINO_PKG" ]; then
  echo "error: pioarduino framework not found at $PIOARDUINO_PKG" >&2
  echo "       run 'pio run' once in the HomePlate repo to install it." >&2
  exit 1
fi
TARGET_FW_VERSION=$(python3 -c 'import json,sys;print(json.load(open(sys.argv[1]))["version"])' "$PIOARDUINO_PKG")
ARDUINO_ESP32_VERSION=$(python3 -c 'import json,sys;print(json.load(open(sys.argv[1]))["version"])' \
  "$HOME/.platformio/packages/framework-arduinoespressif32/package.json" 2>/dev/null || echo "unknown")

DEFCONFIG_SHA=$(sha256sum "$DEFCONFIG" | awk '{print $1}')

mkdir -p "$OUT_DIR"

echo "=== Building slim libbt.a via lib-builder (this takes 30-60 minutes) ==="
echo "    target framework:   $TARGET_FW_VERSION"
echo "    defconfig sha256:   $DEFCONFIG_SHA"

# The container chowns its own output to the host uid so subsequent host-side
# rm/mv work without sudo.
HOST_UID="$(id -u)"
HOST_GID="$(id -g)"

docker run --rm --name homeplate-libbuilder \
  -v "$DEFCONFIG":/opt/esp/lib-builder/configs/defconfig.bleslim:ro \
  -v "$OUT_DIR":/host-out \
  --entrypoint /bin/bash "$IMAGE" -c "
    set -e
    cd /opt/esp/lib-builder
    LIBBUILDER_COMMIT=\$(git rev-parse HEAD)
    LIBBUILDER_SHORT=\$(git rev-parse --short HEAD)
    echo \"=== lib-builder commit: \$LIBBUILDER_COMMIT ===\"

    ./build.sh -t esp32 -b idf-libs bleslim

    IDF_COMMIT=\$(git -C esp-idf rev-parse HEAD 2>/dev/null || echo unknown)
    IDF_BRANCH=\$(git -C esp-idf rev-parse --abbrev-ref HEAD 2>/dev/null || echo unknown)
    IDF_PYTHON=\$(python3 --version 2>&1 | awk '{print \$2}')

    mkdir -p /host-out/lib /host-out/include
    cp -a out/tools/esp32-arduino-libs/esp32/lib/. /host-out/lib/
    cp -a out/tools/esp32-arduino-libs/esp32/include/. /host-out/include/

    # Drop build-side facts into a small env file the host script consumes.
    cat > /host-out/build-info.env <<EOF
LIBBUILDER_COMMIT=\$LIBBUILDER_COMMIT
LIBBUILDER_SHORT=\$LIBBUILDER_SHORT
IDF_COMMIT=\$IDF_COMMIT
IDF_BRANCH=\$IDF_BRANCH
IDF_PYTHON=\$IDF_PYTHON
EOF

    chown -R $HOST_UID:$HOST_GID /host-out
  "

if [ ! -f "$OUT_DIR/lib/libbt.a" ]; then
  echo "error: docker build did not produce $OUT_DIR/lib/libbt.a" >&2
  exit 1
fi
if [ ! -f "$OUT_DIR/build-info.env" ]; then
  echo "error: docker build did not emit build-info.env" >&2
  exit 1
fi

# shellcheck disable=SC1090
source "$OUT_DIR/build-info.env"

echo "=== Refreshing $PREBUILT_DIR ==="
mkdir -p "$PREBUILT_DIR/lib" "$PREBUILT_DIR/include"
# Only carry the libs/headers install.sh actually consumes. Keeping the full
# out/ tree in git would balloon the repo (hundreds of MB of intermediates).
cp -a "$OUT_DIR/lib/libbt.a" "$PREBUILT_DIR/lib/libbt.a"
rm -rf "$PREBUILT_DIR/include/bt"
cp -a "$OUT_DIR/include/bt" "$PREBUILT_DIR/include/bt"

LIBBT_SHA=$(sha256sum "$PREBUILT_DIR/lib/libbt.a" | awk '{print $1}')
BUILT_AT=$(date -u +"%Y-%m-%dT%H:%M:%SZ")

# Write the manifest. install.sh diffs target_framework_version against
# whatever pioarduino has installed and refuses on mismatch. Any field you
# add here should be one-key-per-line so a simple grep/awk parse works.
cat > "$PREBUILT_DIR/manifest.txt" <<EOF
# AUTO-GENERATED by build.sh — do not hand-edit. Re-run build.sh to refresh.
#
# install.sh strictly refuses to install when target_framework_version does
# not equal the installed pioarduino framework's package.json version.
# Mismatch means the prebuilt is stale; see ../README.md to rebuild.

built:                       $BUILT_AT
target_framework_version:    $TARGET_FW_VERSION
arduino_esp32_version:       $ARDUINO_ESP32_VERSION
libbuilder_commit:           $LIBBUILDER_COMMIT
libbuilder_short:            $LIBBUILDER_SHORT
idf_branch:                  $IDF_BRANCH
idf_commit:                  $IDF_COMMIT
idf_python:                  $IDF_PYTHON
defconfig_sha256:            $DEFCONFIG_SHA
libbt_sha256:                $LIBBT_SHA
EOF

echo
echo "=== Build done ==="
echo "  prebuilt/lib/libbt.a    $(ls -la "$PREBUILT_DIR/lib/libbt.a" | awk '{print $5}') bytes"
echo "  prebuilt/include/bt/    $(du -sh "$PREBUILT_DIR/include/bt" | awk '{print $1}')"
echo "  prebuilt/manifest.txt   $TARGET_FW_VERSION"
echo
echo "Commit prebuilt/ to git, then run install.sh to install into pioarduino."
